// Package adr parses ADR files under docs/decisions, renders the INDEX.md
// decision index, and scaffolds new ADR files from the rendered template (awf
// new adr). Generated by awf sync (regenerates docs/decisions/INDEX.md).
package adr

import (
	"errors"
	"fmt"
	"os"
	"path/filepath"
	"regexp"
	"slices"
	"strconv"
	"strings"
	"time"

	"github.com/hypnotox/agentic-workflows/internal/frontmatter"
)

// ADR is a parsed ADR record.
type ADR struct {
	Number        string            // e.g. "0001"
	Title         string            // e.g. "ADR-0001: Template Overlay Rendering Engine"
	Status        string            // e.g. "Accepted"
	Date          string            // frontmatter date, retained verbatim as YYYY-MM-DD text
	Filename      string            // e.g. "0001-template-overlay-rendering-engine.md"
	Path          string            // path as globbed
	Domains       []string          // `domains:` frontmatter (ADR-0014)
	Tags          []string          // `tags:` frontmatter (keyword labels)
	Related       []int             // `related:` frontmatter (ADR numbers)
	Sections      map[string]string // `## ` heading -> non-fenced section body
	DecisionStart int               // raw file byte offset of the Decision heading; 0 when absent
	DecisionEnd   int               // raw file byte offset immediately after the Decision section; 0 when absent

	// Governed fields are populated only for an ADR at or above one of the
	// lock's format cutoffs. A legacy-format record leaves them zero.
	Format     Format         // Legacy, CurrentStateV1, or CurrentStateV2
	NoneState  bool           // State changes section is exactly "None."
	Operations []Operation    // parsed `## State changes` operations
	History    []HistoryEvent // parsed `## Status history` events
}

// Format distinguishes legacy, current-state-v1, and current-state-v2 ADRs.
type Format int

const (
	// Legacy is a pre-cutover ADR: identity, status, and date only.
	Legacy Format = iota
	// CurrentStateV1 is a `format: current-state-v1` ADR with State changes and
	// status-only history.
	CurrentStateV1
	// CurrentStateV2 is a `format: current-state-v2` ADR with heterogeneous
	// status and application history.
	CurrentStateV2
)

// IsV1 reports whether the record was parsed as current-state-v1.
func (a ADR) IsV1() bool { return a.Format == CurrentStateV1 }

// IsV2 reports whether the record was parsed as current-state-v2.
func (a ADR) IsV2() bool { return a.Format == CurrentStateV2 }

// IsGoverned reports whether the record uses either current-state format.
func (a ADR) IsGoverned() bool { return a.IsV1() || a.IsV2() }

// decisionItemRe matches a column-0 numbered Decision item lead. Column-0
// anchoring is load-bearing: 0067 and 0115 carry indented numbered
// sub-lists that must not enumerate (ADR-0120 item 2).
var decisionItemRe = regexp.MustCompile(`(?m)^([0-9]+)\. `)

// DecisionItems returns the numbers of the column-0 numbered items of the
// Decision section, in order of appearance.
func (a ADR) DecisionItems() []int {
	var items []int
	for _, m := range decisionItemRe.FindAllStringSubmatch(a.Sections["Decision"], -1) {
		n, _ := strconv.Atoi(m[1])
		items = append(items, n)
	}
	return items
}

// FilenameRe matches an ADR filename (NNNN-slug.md); group 1 is the 4-digit number.
var FilenameRe = regexp.MustCompile(`^(\d{4})-.+\.md$`)

// ParseDir scans dir for ADR files (NNNN-*.md) and parses each into an ADR.
func ParseDir(dir string) ([]ADR, error) {
	matches, err := filepath.Glob(filepath.Join(dir, "*.md"))
	if err != nil {
		return nil, fmt.Errorf("glob %s: %w", dir, err)
	}
	var adrs []ADR
	for _, path := range matches {
		base := filepath.Base(path)
		m := FilenameRe.FindStringSubmatch(base)
		if m == nil {
			continue // skip INDEX.md, README.md, template.md
		}
		data, err := os.ReadFile(path)
		if err != nil {
			return nil, fmt.Errorf("read %s: %w", base, err)
		}
		a, _, err := ParseBytes(base, data)
		if err != nil {
			return nil, fmt.Errorf("parse %s: %w", base, err)
		}
		a.Path = path
		adrs = append(adrs, a)
	}
	return adrs, nil
}

// adrFrontmatter holds the YAML fields we care about.
type adrFrontmatter struct {
	Format  string   `yaml:"format"`
	Status  string   `yaml:"status"`
	Date    string   `yaml:"date"`
	Domains []string `yaml:"domains"`
	Tags    []string `yaml:"tags"`
	Related []int    `yaml:"related"`
}

// ParseBytes parses one ADR from bytes: status and the other frontmatter
// fields, plus the title from the first `# ` heading. It is the seam the git-blob consumers
// take (ADR-0130 item 5): internal/audit reads history rather than the working
// tree, so it cannot take a Corpus, but it can share the parser and the
// frontmatter schema, which is where the duplication actually was.
//
// found reports whether frontmatter was present at all, which is the tri-state
// the audit needs: absent frontmatter is a legitimate empty status, while
// present-but-unparseable is an error. name is the ADR's base filename, from
// which Filename and Number are derived; Path is left empty, since a
// blob-sourced record has no working-tree path.
func ParseBytes(name string, data []byte) (ADR, bool, error) {
	var fm adrFrontmatter
	body, found, err := frontmatter.Parse(data, &fm)
	if err != nil {
		return ADR{}, found, err
	}
	parsed := sections(string(body), len(data)-len(body))
	a := ADR{Status: fm.Status, Date: fm.Date, Domains: fm.Domains, Tags: fm.Tags, Related: fm.Related, Sections: parsed.bodies}
	switch fm.Format {
	case V1FormatMarker:
		a.Format = CurrentStateV1
	case V2FormatMarker:
		a.Format = CurrentStateV2
	}
	if decision, ok := parsed.ranges["Decision"]; ok {
		a.DecisionStart, a.DecisionEnd = decision.start, decision.end
	}
	for _, line := range strings.Split(string(body), "\n") {
		if strings.HasPrefix(line, "# ") {
			a.Title = strings.TrimPrefix(line, "# ")
			break
		}
	}
	a.Filename = name
	if m := FilenameRe.FindStringSubmatch(name); m != nil {
		a.Number = m[1]
	}
	return a, found, nil
}

type sectionRange struct{ start, end int }

type parsedSections struct {
	bodies map[string]string
	ranges map[string]sectionRange
}

// sections walks Markdown lines, ignoring fenced examples when it derives ADR
// structure. Ranges retain raw file offsets so migrations can edit around an
// opaque fenced block without reserializing the document.
func sections(body string, offset int) parsedSections {
	out := parsedSections{bodies: map[string]string{}, ranges: map[string]sectionRange{}}
	var name string
	var start int
	var b strings.Builder
	var fence byte
	var fenceLen int
	flush := func(end int) {
		if name != "" {
			out.bodies[name] = b.String()
			out.ranges[name] = sectionRange{start: start, end: end}
		}
		b.Reset()
	}
	pos := 0
	for _, rawLine := range rangeLines(body) {
		line := strings.TrimSuffix(rawLine, "\n")
		if marker, n, ok := fenceMarker(line); ok {
			if fence == 0 {
				fence, fenceLen = marker, n
				pos += len(rawLine)
				continue
			}
			if marker == fence && n >= fenceLen && fenceCloser(line, n) {
				fence, fenceLen = 0, 0
			}
			pos += len(rawLine)
			continue
		}
		if fence != 0 {
			pos += len(rawLine)
			continue
		}
		if h, ok := strings.CutPrefix(line, "## "); ok {
			flush(offset + pos)
			name, start = strings.TrimSpace(h), offset+pos
		} else if name != "" {
			b.WriteString(rawLine)
		}
		pos += len(rawLine)
	}
	flush(offset + len(body))
	return out
}

func rangeLines(s string) []string {
	lines := strings.SplitAfter(s, "\n")
	if len(lines) > 0 && lines[len(lines)-1] == "" {
		return lines[:len(lines)-1]
	}
	return lines
}

// fenceMarker identifies a Markdown backtick or tilde fence with up to three
// leading spaces. It returns the marker and its run length.
func fenceMarker(line string) (byte, int, bool) {
	indent := len(line) - len(strings.TrimLeft(line, " "))
	if indent > 3 || indent == len(line) {
		return 0, 0, false
	}
	marker := line[indent]
	if marker != '`' && marker != '~' {
		return 0, 0, false
	}
	n := 0
	for indent+n < len(line) && line[indent+n] == marker {
		n++
	}
	return marker, n, n >= 3
}

// fenceCloser reports whether the marker run is followed only by whitespace.
// Unlike an opening fence, a Markdown closing fence cannot carry info text.
func fenceCloser(line string, n int) bool {
	indent := len(line) - len(strings.TrimLeft(line, " "))
	return strings.TrimSpace(line[indent+n:]) == ""
}

// now returns the current time; overridden in tests for deterministic
// date-stamping (mirrors cmd/awf's getwd/isInteractive seam pattern).
var now = time.Now

// markerLineRe matches an awf-injected marker comment line, so NewFile can
// strip every one - the GENERATED banner and each per-section awf:edit
// provenance pointer - from a copied template.
var markerLineRe = regexp.MustCompile(`(?m)^<!-- (GENERATED by awf|awf:edit).*-->\n`)

// slugNonAlnumRe collapses everything but lowercase letters and digits into a
// single hyphen for slugify.
var slugNonAlnumRe = regexp.MustCompile(`[^a-z0-9]+`)

// AdoptionBoundary validates and seals the existing brownfield ADR identities.
// Every existing decision is legacy at first adoption; current-state-v1 records
// cannot appear below the newly established cutoff.
func AdoptionBoundary(dir string) (cutoff int, gaps []int, err error) {
	corpus, err := LoadCorpus(dir)
	if err != nil {
		return 0, nil, err
	}
	adrs := corpus.All()
	if len(adrs) == 0 {
		return 1, []int{}, nil
	}
	numbers := make([]int, 0, len(adrs))
	seen := map[int]string{}
	for _, a := range adrs {
		n, err := strconv.Atoi(a.Number)
		if err != nil { // coverage-ignore: ParseDir derives Number from FilenameRe
			return 0, nil, err
		}
		if prior, ok := seen[n]; ok {
			return 0, nil, fmt.Errorf("duplicate ADR identity %04d in %s and %s", n, prior, a.Filename)
		}
		if a.IsV1() {
			return 0, nil, fmt.Errorf("ADR %04d declares %s inside the brownfield legacy set", n, V1FormatMarker)
		}
		seen[n] = a.Filename
		numbers = append(numbers, n)
	}
	slices.Sort(numbers)
	cutoff = numbers[len(numbers)-1] + 1
	gaps = []int{}
	for n := 1; n < cutoff; n++ {
		if _, ok := seen[n]; !ok {
			gaps = append(gaps, n)
		}
	}
	return cutoff, gaps, nil
}

// NextNumber returns the next available 4-digit ADR number for dir: one more
// than the highest number ParseDir finds, or "0001" for an ADR-less dir.
// touches-state: adr-system/adr-lifecycle:adr-new-sequential-numbering - NextNumber returns highest-plus-one; proof in adr_test.go
func NextNumber(dir string) (string, error) {
	adrs, err := ParseDir(dir)
	if err != nil {
		return "", err
	}
	max := 0
	for _, a := range adrs {
		n, err := strconv.Atoi(a.Number)
		if err != nil { // coverage-ignore: a.Number is always a 4-digit numeral matched by FilenameRe
			return "", err
		}
		if n > max {
			max = n
		}
	}
	return fmt.Sprintf("%04d", max+1), nil
}

// slugify lowercases title and collapses every run of non-alphanumeric
// characters into a single hyphen, trimming leading/trailing hyphens. A title
// with no alphanumeric characters is a hard error - there is no reasonable
// filename to derive.
func slugify(title string) (string, error) {
	s := slugNonAlnumRe.ReplaceAllString(strings.ToLower(title), "-")
	s = strings.Trim(s, "-")
	if s == "" {
		return "", fmt.Errorf("adr: title %q has no usable characters for a filename", title)
	}
	return s, nil
}

// replaceOnce replaces the first occurrence of old in s, erroring if old is
// absent so a drifted template (a renamed or missing placeholder) fails loudly
// instead of shipping an unresolved placeholder into a committed ADR.
func replaceOnce(s, old, replacement string) (string, error) {
	if !strings.Contains(s, old) {
		return "", fmt.Errorf("adr: template missing expected %q", old)
	}
	return strings.Replace(s, old, replacement, 1), nil
}

// NewFile scaffolds a new ADR under dir: the next sequential number, the
// rendered template.md with every marker comment stripped and its date and
// title heading filled in, named NNNN-slug.md. Refuses to overwrite an
// existing file at that path.
// touches-state: adr-system/adr-lifecycle:adr-new-strips-markers - NewFile strips every marker comment from the copied template; proof in adr_test.go
// touches-state: adr-system/adr-lifecycle:adr-new-heading-matches-file - NewFile fills the heading from the allocated file number; proof in adr_test.go
// touches-state: adr-system/adr-lifecycle:adr-new-no-overwrite - refuse-overwrite guard; unbacked (unreachable), see ADR-0042 Verify note
func NewFile(dir, title string, format Format) (string, error) {
	title = strings.TrimSpace(title)
	number, err := NextNumber(dir)
	if err != nil {
		return "", err
	}
	slug, err := slugify(title)
	if err != nil {
		return "", err
	}
	path := filepath.Join(dir, number+"-"+slug+".md")
	if _, err := os.Stat(path); err == nil { // coverage-ignore: NextNumber always returns one more than every existing NNNN-*.md file, so this path can only pre-exist via a concurrent-process race a single-threaded test cannot construct
		return "", fmt.Errorf("adr: %s already exists", path)
	} else if !os.IsNotExist(err) { // coverage-ignore: Stat fails here only on a permission fault a test cannot trigger
		return "", err
	}
	raw, err := os.ReadFile(filepath.Join(dir, "template.md"))
	if err != nil {
		return "", fmt.Errorf("adr: read template: %w", err)
	}
	content := markerLineRe.ReplaceAllString(string(raw), "")
	marker := V1FormatMarker
	if format == CurrentStateV2 {
		marker = V2FormatMarker
	} else if format != CurrentStateV1 {
		return "", errors.New("adr: scaffold format must be current-state-v1 or current-state-v2")
	}
	block, body, found := frontmatter.Split([]byte(content))
	if !found {
		return "", errors.New("adr: template missing frontmatter")
	}
	var formatMarkers []string
	for _, line := range strings.Split(string(block), "\n") {
		line = strings.TrimSpace(line)
		if strings.HasPrefix(line, "format:") {
			formatMarkers = append(formatMarkers, strings.TrimSpace(strings.TrimPrefix(line, "format:")))
		}
	}
	if len(formatMarkers) == 0 {
		return "", errors.New("adr: template frontmatter missing governed format marker")
	}
	if len(formatMarkers) != 1 {
		return "", errors.New("adr: template frontmatter must contain exactly one governed format marker")
	}
	templateMarker := formatMarkers[0]
	if templateMarker != V1FormatMarker && templateMarker != V2FormatMarker {
		return "", fmt.Errorf("adr: template frontmatter has unsupported governed format marker %q", templateMarker)
	}
	front := strings.Replace(string(block), "format: "+templateMarker, "format: "+marker, 1)
	content = "---\n" + front + "---\n" + string(body)
	date := now().Format("2006-01-02")
	content, err = replaceOnce(content, "date: YYYY-MM-DD", "date: "+date)
	if err != nil {
		return "", err
	}
	content, err = replaceOnce(content, "- YYYY-MM-DD: Proposed", "- "+date+": Proposed")
	if err != nil {
		return "", fmt.Errorf("ADR template Proposed history: %w", err)
	}
	content, err = replaceOnce(content, "# ADR-NNNN: Title", fmt.Sprintf("# ADR-%s: %s", number, title))
	if err != nil {
		return "", err
	}
	if err := os.WriteFile(path, []byte(content), 0o644); err != nil { // coverage-ignore: post-Stat write into a dir just read by NextNumber/ParseDir; fails only on a permission fault a test cannot trigger
		return "", err
	}
	return path, nil
}
